const perplexityData = $input.item.json;
const prepData = $('Prepare Perplexity Request').item.json;

const research = perplexityData.choices ? perplexityData.choices[0].message.content : JSON.stringify(perplexityData);

const prompt = 'You are an ICP specialist for social media marketing. Based on the following market research, create a comprehensive Ideal Customer Profile.\n\nBusiness: ' + prepData.business_url + '\nIndustry: ' + prepData.industry + '\nMarket Research: ' + research + '\n\nReturn a JSON object with keys: icp_summary, demographics, psychographics, content_preferences, competitors, content_opportunities, recommended_hashtags.\n\nReturn ONLY valid JSON, no markdown.';

const body = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  messages: [{ role: 'user', content: prompt }]
});

return { json: { apiBody: body, user_id: prepData.user_id, business_url: prepData.business_url, industry: prepData.industry } };

const input = $input.item.json;
const prepData = $('Prepare ICP Prompt').item.json;

let icpContent = '';
try {
  icpContent = input.content[0].text;
} catch(e) {
  icpContent = JSON.stringify(input);
}

let icpParsed = {};
try {
  icpParsed = JSON.parse(icpContent);
} catch(e) {
  icpParsed = { raw: icpContent };
}

return {
  json: {
    user_id: prepData.user_id,
    business_url: prepData.business_url,
    industry: prepData.industry,
    icp_summary: icpParsed.icp_summary || '',
    demographics: icpParsed.demographics || {},
    psychographics: icpParsed.psychographics || {},
    content_preferences: icpParsed.content_preferences || {},
    competitors: icpParsed.competitors || [],
    content_opportunities: icpParsed.content_opportunities || [],
    recommended_hashtags: icpParsed.recommended_hashtags || [],
    raw_research: icpContent
  }
};
